"""
MKT Christ Commentary — Hebrews chapters 6–9 (gap-fill pass)
Run: python3 scripts/zc-christ-hebrews-6-9-gaps.py

Key decisions:
- ch6 warning/exhortation: theme — every element is Christological in content
- ch7 Melchizedek: shadow pointing to Christ; type-to-antitype argument for superiority
- ch8 heavenly sanctuary + new covenant: direct revelation and Jer 31 fulfillment
- ch9 tabernacle furnishings: each object is a type pointing to Christ (ark=mercy seat; manna=bread of life)
- ch9:16-17 diathēkē as will: direct revelation of why Christ's death was necessary
- ch9:26 once for all at end of ages: definitive eschatological act
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / "data" / "commentary" / source / f"{book}.json"
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / "data" / "commentary" / source / f"{book}.json"
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f"  wrote {p.relative_to(ROOT)}")

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

HEBREWS = json.loads(r"""
{
  "6": {
    "1": "<p>A theme: \"leaving the elementary doctrine of Christ and pressing on to maturity\" — the call to advance beyond the basics of salvation toward the full Christological understanding that chs. 7-10 will provide. The Son is both the foundation of the elementary teaching (repentance, faith, resurrection, judgment) and the content of the mature teaching (the Melchizedekian priesthood, the new covenant, the heavenly sanctuary). The community's growth is growth in understanding what Christ has done and who he is.</p>",
    "2": "<p>A theme: the six elementary items — baptisms, laying on of hands, resurrection, eternal judgment — are all shaped by Christ's own history. Baptism points to his death and resurrection (Rom 6:3-4); laying on of hands to his commissioning and the Spirit's distribution he secured; resurrection to his own resurrection as the firstfruits; eternal judgment to the one to whom all judgment has been given (John 5:22). The catechetical basics are Christological from the start.</p>",
    "3": "<p>A theme: \"and this we will do, if God permits\" — even the community's theological progress toward fuller Christological understanding is dependent on God's enablement. The conditional acknowledges that growing in knowledge of the Son is itself a gift, not a human achievement. The God who spoke in the Son (1:2) is the same God who must enable the community to receive and understand the word the Son has spoken.</p>",
    "4": "<p>A theme: those who have once been enlightened, tasted the heavenly gift, shared in the Holy Spirit, and tasted the powers of the coming age — the community's experience is entirely Christological in its content. The heavenly gift is Christ himself (John 4:10; Rom 6:23); the Holy Spirit is the Spirit of Christ (Rom 8:9; Phil 1:19); the powers of the coming age are the powers of Christ's resurrection life already at work in the community (Eph 1:19-20). To fall away from these is to fall away from Christ.</p>",
    "5": "<p>A theme: tasting \"the goodness of the word of God and the powers of the coming age\" — the word of God that the community has tasted is the word spoken in the Son (1:2); its goodness is the goodness of the salvation he announced and secured. The coming age's powers are already operative through the Son's resurrection — he is the firstfruits of the new creation (1 Cor 15:23), and his resurrection-life flows into the community through the Spirit.</p>",
    "6": "<p>A theme: falling away means \"crucifying once more the Son of God to their own harm and holding him up to contempt\" — apostasy is defined by its Christological content. The one fallen away from is specifically the crucified and risen Son; the act of apostasy re-enacts the crucifiers' verdict on Jesus. This verse defines apostasy as a Christological act: not merely religious indifference but a specific rejection of the person of the Son.</p>",
    "7": "<p>A theme: the land that receives rain and produces useful crops receives God's blessing — the same rain falls on both productive and unproductive land. The rain is the word of the Son, the gifts of the Spirit, the powers of the coming age that the community has received. The productive and unproductive responses to this rain define the difference between those who receive the Son's gift with faith and those who ultimately refuse it.</p>",
    "8": "<p>A theme: land producing thorns and thistles is worthless and near to being cursed — in the end it will be burned. The burning is the judgment that falls on those who received the Son's word and gifts but produced no fruit of faith. The curse of Genesis 3 (thorns and thistles from cursed ground) is the ultimate destiny of the unproductive reception of what Christ has given; the burning is the eschatological judgment.</p>",
    "9": "<p>A direct revelation: though we speak like this, we are convinced of better things in your case — things that belong to salvation. The author's pastoral confidence about the community is itself Christological: the better things are the things of salvation that Christ has secured, and the conviction about the community's belonging to those things is a conviction about their genuine participation in the Son's redemptive work.</p>",
    "10": "<p>A revelation of God: God is not unjust so as to overlook your work and the love you have shown for his name. The character of God revealed here is the character of the Father who notices and remembers every act of love and service done for his people. This is the God who gave his Son for the world — the same divine faithfulness that sent the Son to redeem his people will not overlook the community's faithful service done in the Son's name.</p>",
    "11": "<p>A theme: the call to show the same earnestness to the very end, to make hope sure — the hope that must be made certain is the hope in Christ. Full assurance of hope is confidence in what Christ has secured and will complete. The diligence urged is not self-generated effort but the active maintenance of trust in the one who is both the author and finisher of faith (12:2).</p>",
    "12": "<p>A theme: imitating those who through faith and patience inherit what was promised — the inheritance is the Christological inheritance: sharing in Christ's own sonship, his rest, his kingdom (1:2: \"appointed heir of all things\"). Faith and patience are the posture of those who trust what Christ has secured before it is fully visible. The ancestors who inherited through faith-and-patience are models for receiving what Christ has made available through his completed work.</p>",
    "14": "<p>A shadow: God's oath to Abraham — \"I will surely bless you and multiply you\" (Gen 22:17) — is the foundational divine self-commitment that Christ fulfills. The blessing to Abraham reaches its ultimate expression in the Son (Gal 3:16: \"the promises were spoken to Abraham and to his seed, meaning one person, who is Christ\"). Abraham's oath is the shadow of the greater oath by which Christ was installed as eternal high priest; both together establish the certainty of what God has promised to accomplish in the Son.</p>",
    "15": "<p>A shadow: Abraham received what was promised after waiting patiently — his receiving of Isaac was the beginning of the promise's fulfillment, pointing forward to the final fulfillment in Christ. The pattern of promise → patience → reception that Abraham embodied is the pattern Christ fulfills and makes available to all who believe: the resurrection is the ultimate \"receiving of what was promised\" after the patience of the cross.</p>",
    "16": "<p>A theme: people swear by someone greater, and an oath ends all dispute — the logic of oath-as-maximum-guarantee establishes the context for what follows about the divine self-oath. The human oath-practice is the earthly shadow of the divine oath. When God swears by himself, he places himself as both the surety and the guarantor — which is ultimately what Christ does as the mediator who is himself the guarantee of the better covenant (7:22).</p>",
    "17": "<p>A shadow: God desired to show the heirs of the promise the unchangeable character of his purpose and guaranteed it with an oath — the divine oath to Abraham is the shadow of the oath by which the Son was appointed eternal high priest (Ps 110:4). The \"heirs of the promise\" who are meant to be most strongly encouraged are those who receive the inheritance through the Son, who is himself both the heir of all things (1:2) and the one through whom the promise reaches them.</p>",
    "18": "<p>A direct revelation: two unchangeable things (God's promise and God's oath) give strong encouragement to those who have fled for refuge and laid hold of the hope set before them. The hope is Christ himself — the forerunner who has entered the inner sanctuary (v20). Those who have fled to him have taken refuge in the one whose completed sacrifice and ongoing intercession are the two unchangeable grounds of their hope. The promise and the oath are not abstract guarantees but specific commitments enacted and guaranteed in the Son.</p>",
    "20": "<p>A direct revelation: Jesus, our forerunner, has entered on our behalf into the inner sanctuary — having become a high priest forever according to the order of Melchizedek. The forerunner's entry establishes the path; the \"forever\" establishes its permanence; the \"on our behalf\" establishes its representative character. The risen and ascended Christ has already gone where the community is going — his entry is both the proof that the way is open and the guarantee of their own entry.</p>"
  },
  "7": {
    "2": "<p>A shadow: Melchizedek, whose name means king of righteousness and who is king of Salem (peace), prefigures Christ the King of righteousness and peace (Isa 9:6-7; Jer 23:5-6: \"The LORD our Righteousness\"). The two title-meanings (righteousness and peace) describe the character of the messianic reign: the Messiah brings both the justice that divine righteousness requires and the peace that overcomes the enmity between God and humanity. Melchizedek's double title is the OT shadow of the new covenant's double gift.</p>",
    "3": "<p>A shadow: without father, without mother, without genealogy — the textual silence about Melchizedek's origins and death is designed to prefigure the Son who genuinely has no end of life. The shadow's function here is the negative-correspondence type: the biblical text's unusual silence about what it normally records (genealogy, birth, death) creates a profile that corresponds to the Son's eternal nature. Melchizedek's narrative life begins and ends mysteriously; the Son's life has no beginning or end.</p>",
    "4": "<p>A shadow: \"consider how great this man was, to whom Abraham gave a tenth of the spoils\" — the greatness of the type is the measure of the antitype's greater greatness. If Abraham, the father of the covenant people, paid tithes to Melchizedek, then the Melchizedekian priest is greater than Abraham — and the one who fulfills and surpasses the Melchizedekian pattern is greater still. The argument from the type's greatness establishes the antitype's incomparable stature.</p>",
    "5": "<p>A type: the Levites who receive tithes do so by legal requirement from their own kin who are also Abraham's descendants — the law-based tithe reveals the law-based character of the entire Levitical system. The Levitical priesthood was grounded in the Mosaic law (Torah regulation about Aaronic lineage), not in a direct divine oath. This characteristic — law-grounded rather than oath-grounded — is the type's limitation that the Melchizedekian antitype overcomes.</p>",
    "6": "<p>A shadow: Melchizedek, not genealogically traceable to Levi, nonetheless collected the tithe from Abraham and blessed him who had the promises — the greater priesthood pre-existed and surpasses the Levitical priesthood. This shadow-priest who operates outside the Levitical system but towers above it foreshadows Christ who comes from a different tribe (Judah) but holds a higher priesthood than the Aaronic. The type's superiority over the Levitical system prefigures the antitype's definitive superiority.</p>",
    "7": "<p>A shadow: the lesser is blessed by the greater — this axiom establishes the hierarchy: Melchizedek blessed Abraham, so Melchizedek is greater. And if Melchizedek is greater than Abraham (from whom all Levitical priests descend), then the one who fulfills the Melchizedekian priesthood is greater than all Levitical priests. The logical chain runs from Melchizedek's blessing → Abraham's lesser status → all Levites within Abraham → Christ as the Melchizedekian priest is greater than all.</p>",
    "8": "<p>A shadow: in the Levitical case, mortal men receive tithes; in Melchizedek's case, one who is testified to be living receives them. The \"testified to be living\" (from the text's silence about his death) is the shadow of the one who genuinely lives forever — the risen Christ whose indestructible life is the basis of his permanent priesthood (v16). The mortal-versus-living-one contrast anticipates the core claim: Christ's priesthood is permanent precisely because his resurrection life is permanent.</p>",
    "9": "<p>A shadow: one might say that even Levi, through Abraham, paid tithes to Melchizedek — the entire Levitical system, in its ancestor, subordinated itself to the Melchizedekian priesthood. This means the Levitical system was always in a position of subordination to the type that Christ fulfills — it was never the highest or final form of priesthood but always subordinate to the order it shadowed. The argument establishes that the Levitical system implicitly acknowledged the Melchizedekian order's superiority from the very beginning.</p>",
    "10": "<p>A shadow: Levi was in the loins of Abraham when Melchizedek met him — the corporate solidarity that makes all descendants of Abraham participants in Abraham's tithing also makes all Levitical priests participants in the acknowledgment of the Melchizedekian superiority. Every Levitical high priest who ever served was, in his ancestor, already bowing to the one whose priesthood Christ fulfills. The shadow-acknowledgment was built into the system's very genealogy.</p>",
    "11": "<p>A direct revelation: if perfection were attainable through the Levitical priesthood, why would there be need for another priest to arise according to the order of Melchizedek? The existence of Psalm 110:4's promise is the proof that the Levitical system could not achieve the telos — the final goal of the priestly office, which is the complete restoration of the human-divine relationship. Christ's appointment to the Melchizedekian order is the announcement that the system designed to point forward had arrived at its destination.</p>",
    "12": "<p>A direct revelation: when there is a change of priesthood, there is necessarily a change of law as well. The law-priesthood nexus means that the coming of the new Melchizedekian priest (Christ) entails a reorganization of the entire legal structure. This is not the abolition of the Torah but its fulfillment and replacement by the new covenant's internalized law (Jer 31:33). Christ does not negate the law but brings it to its telos (Rom 10:4: \"Christ is the telos of the law for righteousness to everyone who believes\").</p>",
    "13": "<p>A direct revelation: the one of whom these things are said belonged to a different tribe, from which no one has ever served at the altar. The historical fact that Jesus was from Judah establishes that his priesthood cannot be grounded in the Mosaic-Levitical system — he had no standing there by law. This apparent disqualification from the Levitical perspective is exactly the proof that his priesthood operates on a different and higher principle: the divine oath that transcends tribal genealogy.</p>",
    "14": "<p>A direct revelation: our Lord descended from Judah, and Moses said nothing about priests from that tribe. The Davidic lineage of Christ (Rom 1:3; Matt 1:1-17) fulfills the royal messianic promises (2 Sam 7:12-16; Isa 11:1-5) while simultaneously demonstrating that his priestly role must be grounded in a different order. Judah + priesthood = Melchizedekian order, not Aaronic. The specific genealogical fact proves the specific theological category.</p>",
    "15": "<p>A direct revelation: it is even more evident if another priest arises in the likeness of Melchizedek — the analogy strengthens the argument. Christ's appearance as a Melchizedek-like priest (king and priest, without genealogical limitation, eternal) is the historical event that confirms what the typology had anticipated. The \"likeness\" is not mere similarity but typological correspondence: Christ fits the Melchizedekian pattern because Melchizedek was shaped by the divine design to correspond to the Son.</p>",
    "16": "<p>A direct revelation: one who has become a priest not according to a legal requirement about bodily descent but according to the power of an indestructible life. The indestructible life is the resurrection life of Christ — the life that death could not hold (Acts 2:24). His priesthood is grounded not in the biological-genealogical order (which is subject to death) but in the resurrection order that transcends death. The resurrection is the proof and the grounds of his eternal priesthood.</p>",
    "17": "<p>A fulfillment: \"You are a priest forever, in the order of Melchizedek\" — the Psalm 110:4 divine oath is fulfilled in the risen and ascended Christ. The \"forever\" of the oath finds its historical fulfillment in the one whose resurrection makes \"forever\" a biological reality rather than merely a legal fiction. Christ is priest forever because he lives forever; the oath's fulfillment is ontological, not merely legal.</p>",
    "18": "<p>A direct revelation: the former commandment is set aside because of its weakness and uselessness — the Levitical law's setting-aside is the direct consequence of the Melchizedekian priest's arrival. Christ's coming does not supplement the Levitical system but supersedes it, because the system was designed to point toward what has now arrived. The weakness and uselessness is the type's structural limitation: it could describe but not achieve what the antitype delivers.</p>",
    "19": "<p>A direct revelation: the law made nothing perfect, and a better hope is introduced through which we draw near to God. The better hope is Christ himself — the one through whom the community now approaches what the entire Levitical system pointed toward but could not deliver: actual, permanent, direct access to God. \"We draw near to God\" (using the priestly language of liturgical approach) is now the community's reality through Christ's completed high priesthood.</p>",
    "20": "<p>A direct revelation: it was not without an oath — the contrast between oath-less Levitical ordination and oath-secured Melchizedekian appointment establishes the higher authority of Christ's priesthood. Human priestly appointments could be revoked (and were, repeatedly, in Second Temple history); the divine oath cannot be revoked (v21: \"The Lord has sworn and will not change his mind\"). The oath-security of Christ's priesthood is the guarantee of the salvation it secures.</p>",
    "21": "<p>A fulfillment: \"The Lord has sworn and will not change his mind: You are a priest forever\" — the irrevocable divine oath completes the argument for Christ's permanent priesthood. The oath's two elements (sworn = maximally guaranteed; will not change his mind = permanent) establish both the certainty and the permanence of Christ's priestly appointment. No political power, no historical contingency, no subsequent event can revoke what God has sworn to maintain.</p>",
    "23": "<p>A type: there were many Levitical priests because death prevented each one from continuing — the plurality of priests is the type's limitation that the antitype overcomes. Each new appointment pointed to the inadequacy of the previous priest — his death proved the work unfinished. The ever-lengthening list of high priests is the type's cry for a priest who does not die: the list's end comes when a priest appears whose life death cannot terminate.</p>",
    "24": "<p>A direct revelation: because Jesus lives forever, he holds his priesthood permanently. The permanent priesthood is the Christological consequence of the resurrection: the one who died and rose holds the priestly office that no one can take from him. Every benefit of the Melchizedekian priesthood — the eternal intercession, the complete salvation, the permanent access — flows from this single fact: he lives forever.</p>",
    "26": "<p>A direct revelation: such a high priest truly meets our need — holy, blameless, unstained, separated from sinners, and exalted above the heavens. The five moral and status qualifiers describe what the ideal high priest must be: morally perfect (holy, blameless, unstained), relationally distinct from the problem he addresses (separated from sinners), and positionally supreme (exalted above the heavens). Christ meets every qualification simultaneously — the one the Levitical system was always seeking to approximate has arrived.</p>",
    "28": "<p>A direct revelation: the law appoints as high priests men who are weak, but the oath — which came after the law — appoints the Son who has been made perfect forever. The contrast summarizes the entire Melchizedek argument: law produces weak priests; divine oath produces the perfect Son. The \"made perfect forever\" is the completed, permanent qualification earned through the incarnation, death, resurrection, and ascension. The Son is not merely better than the Levitical priests but definitively and permanently qualified in a way they never could be.</p>"
  },
  "8": {
    "2": "<p>A direct revelation: Christ serves in the sanctuary, the true tabernacle set up by the Lord, not by man. The contrast between the handmade (earthly) and the Lord-made (heavenly) sanctuaries defines where Christ's ministry operates: not in the shadow but in the reality, not in the copy but in the original. His ministry in the true tabernacle is the fulfillment of everything the earthly tabernacle anticipated — the location tells us the quality: this is the real thing, not the prototype.</p>",
    "3": "<p>A direct revelation: every high priest is appointed to offer gifts and sacrifices, so it was necessary for this one also to have something to offer. The necessity of Christ's offering establishes the continuity between his priesthood and the Levitical type: the structure (priest must offer) is the same; the content (what he offers) is different. He has something to offer — himself. The type required the priest to bring an animal; the antitype brings himself. The structure is fulfilled; the content is transformed.</p>",
    "4": "<p>A direct revelation: if he were on earth, he would not be a priest at all, since there are priests who offer gifts under the law. Christ's earthly non-priestly status (he was from Judah, not Levi; he performed no Levitical service) is itself a Christological marker: his priesthood operates in the heavenly sphere, not the earthly one. The earthly and heavenly are not competing claims but complementary ones — the earthly system was the shadow; the heavenly is the substance that Christ operates within.</p>",
    "5": "<p>A shadow: the Levitical priests serve a copy and shadow of the heavenly things — the Moses-pattern-on-the-mountain command establishes the entire earthly sanctuary as derivative from the heavenly original. The earthly tabernacle is the most sacred institution in Israel's history, and Hebrews calls it a \"shadow\" — not to devalue it but to reveal its nature. Shadows are real (they are cast by real objects) but they are not the objects themselves. The tabernacle was real revelation of the heavenly; Christ is the heavenly reality itself.</p>",
    "7": "<p>A direct revelation: if that first covenant had been faultless, no place would have been sought for another. The existence of Jeremiah's new covenant promise is the canonical proof that God himself acknowledged the Mosaic covenant's incompleteness. Christ's coming is therefore not a surprise or a course-correction but the arrival of what the first covenant was designed to herald. The first covenant was not a failure but a preparation; its inadequacy was by divine design, pointing forward to the covenant that Christ would inaugurate.</p>",
    "9": "<p>A fulfillment: \"Not like the covenant I made with their fathers when I took them by the hand to lead them out of Egypt\" — the Sinai covenant's contrast with the new covenant defines what the new covenant is not and therefore what it is. The old covenant was external (stone tablets), mediated (through Moses), and conditional (on Israel's faithfulness that they consistently failed to maintain). The new covenant that Christ inaugurates is internal (law on hearts), immediate (all will know God), and secured by God's own faithfulness rather than Israel's.</p>",
    "10": "<p>A fulfillment: \"I will put my laws in their minds and write them on their hearts, and I will be their God, and they will be my people\" — the internalized law of the new covenant is the Christ-given Spirit's work. The Spirit of Christ (Rom 8:9; 2 Cor 3:3) writes on the heart what the stone tablets could only inscribe externally. The covenant-formula (\"I will be their God, they will be my people\") reaches its full expression in the community that is united to Christ — the head of the people who are his body.</p>",
    "11": "<p>A fulfillment: \"No longer will each one teach his neighbor or his brother, saying Know the Lord, for they shall all know me, from the least to the greatest\" — the direct, universal God-knowledge of the new covenant is mediated through Christ the supreme teacher and revelation of the Father. The new covenant's universal God-knowledge is not the abolition of teaching but the transformation of its basis: not \"learn about God\" but \"deepen your knowledge of the God you already know through Christ\" (John 17:3: \"this is eternal life, that they know you, the only true God, and Jesus Christ whom you have sent\").</p>",
    "12": "<p>A fulfillment: \"For I will be merciful toward their iniquities, and I will remember their sins no more\" — the complete and permanent forgiveness of the new covenant is grounded in Christ's completed sacrifice. The promise's fulfillment is the specific consequence of the one offering that purified the conscience and secured eternal redemption (9:14; 10:14). \"I will remember their sins no more\" is not a divine memory-failure but the covenant-completion that Christ's blood achieved: the record is permanently cleared.</p>",
    "13": "<p>A direct revelation: in speaking of a new covenant, God made the first one obsolete; what is growing old and aging will soon disappear. The obsolescence of the Mosaic covenant is not a judgment on its value but the declaration of its completed purpose: the shadow retires when the substance arrives. The Levitical system was always designed to be temporary — its annual cycles, its repeated sacrifices, its graduated access were all pointing forward to the once-for-all, fully open access that Christ secured. The \"soon disappear\" anticipates the Temple's destruction (70 CE) as the visible completion of what Christ's death and resurrection had already accomplished covenantally.</p>"
  },
  "9": {
    "1": "<p>A shadow: the first covenant had regulations for worship and an earthly sanctuary — the entire cultic structure of the Mosaic covenant is the elaborate shadow of the heavenly reality. The \"regulations for worship\" are the type's rules; the \"earthly sanctuary\" is the type's location. Both the rules and the location point beyond themselves: the regulations to the perfect priestly service Christ renders; the earthly sanctuary to the heavenly sanctuary where Christ ministers.</p>",
    "2": "<p>A shadow: in the outer room were the lampstand and the table with the bread of the Presence — the furnishings of the Holy Place are the type's first level. The lampstand (light in the sanctuary) prefigures Christ as the light of the world (John 8:12) and the community's illumination through him. The showbread (the bread of the Presence, renewed weekly) prefigures Christ as the bread of life (John 6:35, 48) — the permanent presence of nourishment before God in the true sanctuary.</p>",
    "3": "<p>A shadow: behind the second curtain was the Most Holy Place — the graduated access structure of the tabernacle, with the most restricted inner room, is the type of the graduated access that Christ's death tore open. The curtain that blocked all but the high priest's once-yearly entry is the same curtain that was torn from top to bottom at the crucifixion (Matt 27:51) — the type's restriction is removed by the antitype's completed sacrifice.</p>",
    "4": "<p>A shadow: the Most Holy Place contained the golden altar of incense, the ark of the covenant, the golden jar of manna, Aaron's staff, and the stone tablets — each object in the type points to Christ. The incense altar (the priestly intercession) → fulfilled in Christ's permanent intercession (7:25). The manna (God's wilderness provision) → fulfilled in Christ as the bread of life (John 6:49-51). Aaron's staff that budded (divine vindication of priesthood through new life) → fulfilled in Christ's resurrection as the divine validation of his priesthood. The stone tablets (the covenant law) → fulfilled in the internalized law of the new covenant (8:10).</p>",
    "5": "<p>A shadow: above the ark were the cherubim of Glory overshadowing the mercy seat — the mercy seat (<em>kapporet</em>, the place of atonement) where the blood was sprinkled on Yom Kippur is the type fulfilled in Christ as the mercy seat (Rom 3:25: God set forth Christ as a <em>hilastērion</em> — the same word as the LXX uses for the mercy seat). The glory-cherubim overshadowing the place of atonement is the type of the divine glory that overshadows the true mercy seat — Christ's sacrifice — in the heavenly sanctuary.</p>",
    "6": "<p>A shadow: the priests entered the outer room regularly to perform their ministry — the daily priestly ministry in the Holy Place is the shadow of Christ's ongoing heavenly ministry. The lampstand-tending (maintaining the light) and incense-burning (intercession) that occupied the priests daily correspond to Christ's permanent heavenly intercession. The regularity of the earthly priestly routine is the shadow of the permanence of Christ's heavenly service — the shadow's repetition anticipated the antitype's permanence.</p>",
    "8": "<p>A shadow: the Holy Spirit was indicating through the tabernacle arrangement that the way into the Most Holy Place was not yet open while the first tabernacle was still standing. The tabernacle's restricted access was a Spirit-designed pedagogical statement: the divine presence was both present and inaccessible under the old covenant — a living visual parable of the coming solution. Christ's death opens what the curtain blocked; the Spirit who designed the restriction is the same Spirit who announces the opening.</p>",
    "9": "<p>A shadow: this was a parable for the present time, indicating that gifts and sacrifices offered could not perfect the worshiper's conscience. The entire tabernacle is a divinely designed parable — its external rituals point to an internal transformation they could not achieve. The conscience that needed cleansing (the moral-spiritual interior) was the target the type could only gesture toward. Christ's blood achieves what the parable gestured toward: the conscience is cleansed (9:14), not merely covered.</p>",
    "10": "<p>A shadow: the regulations about food and drink and various washings — bodily regulations applying until the time of reformation — are the type's external dimension. Everything in the Levitical system that dealt with bodily purity was pointing forward to the spiritual purity that Christ's blood achieves. The \"time of reformation\" (<em>kairos diorthōseōs</em>) is the Christ-event: the time when God set right what the shadow had gestured toward.</p>",
    "12": "<p>A direct revelation: Christ entered the most holy place once for all, not with the blood of goats and calves but with his own blood, thus securing an eternal redemption. The three contrasts with the Levitical Day of Atonement — once for all vs. annually; own blood vs. animal blood; eternal redemption vs. repeated coverage — define the qualitative difference. His entry was the fulfillment of every Yom Kippur in Israel's history: the event toward which all those annual approaches were pointing.</p>",
    "13": "<p>A type: the blood of goats and bulls and the ashes of the red heifer sanctify those who are defiled, purifying the flesh. The Levitical purification is genuine but limited: it achieves external, ceremonial cleanness. The type's achievement (genuine external purification) is the shadow of the antitype's greater achievement (genuine internal purification of the conscience). The type's reality establishes the <em>a fortiori</em> argument: if the shadow achieves this much, how much more does the substance achieve?</p>",
    "14": "<p>A direct revelation: the blood of Christ, who through the eternal Spirit offered himself without blemish to God, will purify our conscience from dead works to serve the living God. The conscience-purification that the Levitical type could not achieve is what Christ's blood accomplishes. The eternal Spirit's involvement in the self-offering connects the cross to the entire Trinitarian divine action: the Father sends the Son, the Son offers himself, the Spirit enables the offering that the Father accepts. The purified conscience is then free for the worship that was always the goal: serving the living God.</p>",
    "15": "<p>A fulfillment: Christ is the mediator of a new covenant, so that those who are called may receive the promised eternal inheritance, since a death has occurred that redeems them from transgressions committed under the first covenant. The death that redeems from under the first covenant's penalty is Christ's death; the eternal inheritance they receive is the sonship-inheritance that the Son shares with all who belong to him (1:2: \"heir of all things\"). The new covenant mediator does not replace the covenant structure but fulfills it: the death that the covenant required has occurred in the mediator himself.</p>",
    "16": "<p>A direct revelation: where a covenant (will) is made, the death of the one making it must be established. The double meaning of <em>diathēkē</em> (covenant/will) enables the argument: Christ's death is both the covenant-inauguration (his blood is \"the blood of the covenant,\" v20) and the will-activation (his death activates the distribution of the promised inheritance). The testator-Messiah is both the one who makes the will and the one whose death activates it — a unique legal situation with no human parallel.</p>",
    "17": "<p>A direct revelation: a will takes effect only at death; it has no force while the testator lives. Christ's death is therefore the necessary precondition for the distribution of everything he promised his community — the Holy Spirit (John 16:7: \"I will send the Counselor to you\"), the forgiveness of sins, the resurrection hope, the eternal inheritance. Everything that belongs to the Son becomes available to those who receive it through his death. The cross is the moment the will becomes operative.</p>",
    "18": "<p>A type: even the first covenant was inaugurated with blood. The Sinai blood-sprinkling (Exod 24:3-8) is the type of the new covenant's inauguration at the Last Supper and the cross. The pattern — covenant-making requires blood — runs through both covenants, establishing the principle: covenants that address the problem of human sin require the death that sin's penalty demands. The type's blood-inauguration anticipates the antitype's blood-inauguration; the Sinai blood points forward to the cross-blood.</p>",
    "19": "<p>A type: Moses sprinkled the scroll of the law and all the people with blood, water, scarlet wool, and hyssop. The Sinai blood-sprinkling covered the covenant document and the covenant people — both were consecrated by blood. The type establishes that both the law and the people must be blood-covered to stand before God. In the antitype, Christ's blood covers not just the law's requirements but the people's consciences — the new covenant's blood reaches what the Sinai blood only touched externally.</p>",
    "20": "<p>A type: \"This is the blood of the covenant that God commanded you to observe\" — the Sinai covenant-formula that Jesus reuses at the Last Supper (Matt 26:28: \"This is my blood of the covenant\"). The echo is intentional and Christological: Jesus positions his blood as the fulfillment of the Sinai blood-of-the-covenant, the new covenant-inauguration that the Sinai ceremony was pointing toward. The type's formula is quoted by the antitype, claiming correspondence and fulfillment simultaneously.</p>",
    "21": "<p>A type: Moses sprinkled the tabernacle and all the vessels of ministry with blood. The comprehensive blood-consecration of the entire Mosaic worship system establishes that everything involved in approaching God required blood. The principle is total: no approach to God without the blood that covers the approach. In the antitype, Christ's blood is the one comprehensive consecration that covers all approaches — every prayer, every act of worship, every approach to the throne of grace comes through the blood that permanently consecrates the way.</p>",
    "22": "<p>A type: under the law almost everything is purified with blood, and without the shedding of blood there is no forgiveness. The type establishes the blood-forgiveness nexus as the structure of the entire approach to God. This principle reaches its ultimate expression in Christ's self-offering: the blood that achieves the final, complete, permanent forgiveness that all the Levitical blood-shedding anticipated. The \"almost everything\" of the Levitical system becomes the \"one thing\" of Christ's sacrifice.</p>",
    "23": "<p>A type and fulfillment: the copies of the heavenly things required these purifications, but the heavenly things themselves required better sacrifices. The type-purifications were real but partial; the antitype-purification is complete and final. The \"better sacrifices\" (singular in effect though plural in formulation) is Christ's one self-offering that purifies not just the earthly copies but the heavenly originals — the community's approach to the divine throne is itself purified by the blood that covers it.</p>",
    "25": "<p>A direct revelation: Christ did not enter to offer himself again and again, as the high priest enters the Most Holy Place with blood not his own every year. The non-repetition of Christ's sacrifice is one of the most theologically significant facts in Hebrews: the once-for-all character of the cross is the proof of its completeness. Annual repetition was the type's tacit admission that last year's sacrifice was insufficient; the non-repetition of Christ's sacrifice is the declaration that his sacrifice was fully sufficient — nothing needs to be added, nothing repeated.</p>",
    "26": "<p>A direct revelation: Christ appeared once for all at the end of the ages to put away sin by the sacrifice of himself. The \"end of the ages\" (<em>synteleia tōn aiōnōn</em>) frames the crucifixion as the eschatological hinge-point of history — the moment when God acted definitively to address what all prior history had been building toward. \"Putting away sin\" (<em>athetēsis</em>: legal annulment) describes the cross as the definitive legal resolution of the sin-problem that all the Levitical sacrifices had been acknowledging and managing.</p>",
    "27": "<p>A theme: it is appointed for humans to die once, and after that comes judgment. The universal human appointment (one death, one judgment) is the framework against which Christ's own single death and eschatological appearing (v28) are placed. Human mortality is not incidental to the argument but the structure within which Christ's representative humanity operates: he dies the one death (in the place of the many), and at his second appearing the judgment that follows death becomes the salvation for those he represents.</p>"
  }
}
""")

def main():
    existing = load_comm("mkt-christ", "hebrews")
    merge_comm(existing, HEBREWS)
    save_comm("mkt-christ", "hebrews", existing)
    total = sum(len(v) for v in existing.values())
    print(f"Hebrews 6-9 mkt-christ gaps filled: {len(existing)} chapters, {total} verses written.")

if __name__ == "__main__":
    main()
